class Solution {
    private static final int MOD = 1000000007;
    public int numberOfArrays(String s, int k) {
        int n = s.length();
        int[] dp = new int[n + 1];
        dp[0] = 1;
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= 10 && j <= i; j++) {
                String substr = s.substring(i - j, i);
                if (substr.length() > 1 && substr.charAt(0) == '0') {
                    continue;
                }
                long num = Long.parseLong(substr);
                if (1 <= num && num <= k) {
                    dp[i] = (dp[i] + dp[i - j]) % MOD;
                }
            }
        }
        return dp[n];
    }
}
